import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            long N = Long.parseLong(br.readLine().trim());
            long total = N >= 111 ? N - 111 + 1 : 0;
            long a = N / 222;          // multiples of 222
            long b = N / 333;          // multiples of 333
            long c = N / 555;          // multiples of 555
            long ab = N / 666;         // lcm(222,333)
            long ac = N / 1110;        // lcm(222,555)
            long bc = N / 1665;        // lcm(333,555)
            long abc = N / 3330;       // lcm(222,333,555)
            long union = a + b + c - (ab + ac + bc) + abc;
            long ans = total - union;
            out.append(ans);
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

